import{_ as e,o as a,c as o,Q as t}from"./chunks/framework.18a20c57.js";const m=JSON.parse('{"title":"介绍","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"introduction.md","filePath":"introduction.md"}'),r={name:"introduction.md"},n=t('<h1 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h1><p><code>miniprogram-design</code>的设计初衷是允许将视图组件完全与可视化编辑的功能剥离开来，一方面让开发的关注点下沉，不需要考虑可视化的基础功能，能够快速进行业务组件的开发; 另一方面是能够快速接入不同的项目。</p><h2 id="业务与功能分离" tabindex="-1">业务与功能分离 <a class="header-anchor" href="#业务与功能分离" aria-label="Permalink to &quot;业务与功能分离&quot;">​</a></h2><p>依赖<code>module-federation</code>让业务组件可以与可视化功能分离开。简单的说编辑器本身可以独立部署，而业务组件可以在本地开发。这也是与常见的可视化编辑器的不同地方，要么是颗粒度太细，导致使用起来很麻烦，上手门槛比较高; 要么是单纯通过json配置，比较死板。</p><h2 id="快速部署" tabindex="-1">快速部署 <a class="header-anchor" href="#快速部署" aria-label="Permalink to &quot;快速部署&quot;">​</a></h2><p>支持通过<code>docker</code>来快速部署，运行后可以通过端口直接访问，或者是在网关进行简单的匹配转发。</p>',6),i=[n];function d(c,s,_,l,h,p){return a(),o("div",null,i)}const f=e(r,[["render",d]]);export{m as __pageData,f as default};
